"""Shared helpers for the unified eval runner (eval.run)."""
from __future__ import annotations

import json
import statistics
from pathlib import Path

from . import attacks, config, null_inputs
from .deliverable import Bundle
from .rubric import RubricItem

# Where rollout deliverables generated by eval.policy are written.
ROLLOUTS = config.ROOT / "eval" / "rollouts"

# --- axis thresholds (shared by the judge runner and the iterator) ----------
LEAK_THRESHOLD = 0.5      # a null earning >=50% of a positive item's points = leak
NULL_HACK_SCORE = 0.30    # a null scoring above this is a reward-hacking suspect


def load_task(task_folder: str) -> dict:
    return json.loads((config.DATA / task_folder / "task.json").read_text())


def has_gold(task_folder: str) -> bool:
    return bool(load_task(task_folder).get("deliverable_files"))


def reference_dir(task_folder: str) -> Path:
    return config.DATA / task_folder / "reference_files"


def gold_bundle(task_folder: str) -> Bundle:
    return Bundle.with_references(
        "gold",
        config.DATA / task_folder / "deliverable_files",
        reference_dir(task_folder),
    )


def null_bundle(task_folder: str, variant: str, variant_dir: Path) -> Bundle:
    """Wrap a synthesized null deliverable with the same read-only reference files."""
    return Bundle.with_references(variant, variant_dir, reference_dir(task_folder))


def rollout_dir(task_folder: str, policy_key: str) -> Path:
    """Directory holding a policy's generated deliverable files for a task."""
    return ROLLOUTS / task_folder / policy_key / "deliverable"


# --- subject resolution -----------------------------------------------------
# A "subject" is whatever a judge grades, named by a short string on the CLI:
#   gold                      the released gold deliverable (oracle, ~1)
#   blank | unedited_input    a synthesized do-nothing null (~0); from null_inputs
#   attack:<name> | <name>    a mechanical reward-hacking deliverable; from attacks
#                             (restate_input | keyword_stuff | presence_max | stems_named)
#   rollout:<policy_key>      a deliverable produced by eval.policy for <policy_key>
#   preexisting:<path>        files under <path> (or <path>/<task_folder>)

def available_subjects(task_folder: str) -> list[str]:
    """The default boundary subjects for a task: gold plus any synthesized nulls."""
    subs = ["gold"] if has_gold(task_folder) else []
    subs += list(null_inputs.build_nulls(task_folder))
    return subs


def attack_subjects(task_folder: str) -> list[str]:
    """The hackability attack subjects for a task (Axis 2).

    The mechanical attacks need no gold and are always available; the LLM
    `adversarial` agent is included only once it has been generated on disk
    (it is expensive, so it is built explicitly via `python -m eval.attacks
    --adversarial <task>`, never auto-built during a judge sweep)."""
    subs = list(attacks.attack_names(task_folder))
    if attacks.has_adversarial(task_folder):
        subs.append(attacks.ADVERSARIAL_NAME)
    return subs


def hack_subjects(task_folder: str) -> list[str]:
    """Cheap subjects whose passing a positive item counts as a leak: nulls + attacks."""
    return list(null_inputs.build_nulls(task_folder)) + attack_subjects(task_folder)


def resolve_subject(task_folder: str, subject: str) -> Bundle:
    """Map a subject string to a gradeable Bundle (deliverable + read-only references)."""
    if subject == "gold":
        if not has_gold(task_folder):
            raise SystemExit(f"{task_folder}: no gold deliverable released")
        return gold_bundle(task_folder)

    if subject.startswith("rollout:"):
        key = subject.split(":", 1)[1]
        d = rollout_dir(task_folder, key)
        if not d.exists() or not any(d.iterdir()):
            raise SystemExit(
                f"{task_folder}: no rollout for policy '{key}' "
                f"(run --mode rollout --policy-models {key} first)")
        return Bundle.with_references(subject, d, reference_dir(task_folder))

    if subject.startswith("preexisting:"):
        root = Path(subject.split(":", 1)[1]).expanduser()
        d = root / task_folder if (root / task_folder).is_dir() else root
        if not d.is_dir():
            raise SystemExit(f"{task_folder}: no preexisting outputs at {d}")
        return Bundle.with_references(subject, d, reference_dir(task_folder))

    # attack:<name> or a bare attack variant name (hackability subjects, Axis 2)
    name = subject.split(":", 1)[1] if subject.startswith("attack:") else subject

    # The LLM adversarial agent is generated out-of-band and resolved from disk
    # (never auto-built here, since it costs API calls).
    if name == attacks.ADVERSARIAL_NAME:
        if not attacks.has_adversarial(task_folder):
            raise SystemExit(
                f"{task_folder}: no adversarial deliverable generated yet "
                f"(run: python -m eval.attacks --adversarial {task_folder})")
        return Bundle.with_references(subject, attacks.adversarial_dir(task_folder),
                                      reference_dir(task_folder))

    atk = attacks.build_attacks(task_folder)
    if name in atk:
        return Bundle.with_references(subject, atk[name], reference_dir(task_folder))

    # otherwise treat it as a null variant name (blank / unedited_input / ...)
    nulls = null_inputs.build_nulls(task_folder)
    if subject not in nulls:
        raise SystemExit(
            f"{task_folder}: unknown subject '{subject}' (have: gold, "
            f"{', '.join(nulls) or 'no nulls'}, {', '.join(atk) or 'no attacks'}, "
            f"rollout:<key>, preexisting:<path>)")
    return null_bundle(task_folder, subject, nulls[subject])


def is_null_subject(task_folder: str, subject: str) -> bool:
    """True for synthesized do-nothing nulls (used by the boundary analysis)."""
    return subject in null_inputs.build_nulls(task_folder)


def is_attack_subject(task_folder: str, subject: str) -> bool:
    """True for reward-hacking attacks — mechanical or the LLM adversarial agent."""
    name = subject.split(":", 1)[1] if subject.startswith("attack:") else subject
    return name in attacks.attack_names(task_folder) or name == attacks.ADVERSARIAL_NAME


def all_tasks() -> list[str]:
    return sorted(p.name for p in config.DATA.iterdir() if p.is_dir())


def tasks_with_gold() -> list[str]:
    return [t for t in all_tasks() if has_gold(t)]


def stdev(xs: list[float]) -> float:
    return statistics.pstdev(xs) if len(xs) > 1 else 0.0


# --- shared dispersion / boundary analysis ----------------------------------
# Used by both the judge runner (eval.run) and the rubric iterator (eval.iterate).

def agreement(items: list[RubricItem], runs: list[dict]) -> dict:
    """Per-item dispersion across a set of scorecards (binarized at 0.5).

    `runs` are normalize() dicts for the SAME subject (different judges for
    cross-model, or repeats of one judge for self-consistency)."""
    per_item = []
    for it in items:
        fracs = [r["per_item"][it.id]["fraction"] for r in runs]
        binar = [1 if f >= 0.5 else 0 for f in fracs]
        per_item.append({
            "id": it.id, "criterion": it.criterion,
            "mean": round(sum(fracs) / len(fracs), 3),
            "stdev": round(stdev(fracs), 3),
            "unanimous": len(set(binar)) == 1,
        })
    totals = [r["normalized"] for r in runs]
    frac_unanimous = sum(1 for p in per_item if p["unanimous"]) / len(per_item)
    return {
        "total_scores": [round(t, 3) for t in totals],
        "total_mean": round(sum(totals) / len(totals), 3),
        "total_stdev": round(stdev(totals), 3),
        "frac_items_unanimous": round(frac_unanimous, 3),
        "mean_item_stdev": round(sum(p["stdev"] for p in per_item) / len(per_item), 3),
        "per_item": per_item,
        "most_contested": sorted(per_item, key=lambda p: -p["stdev"])[:8],
    }


def leaks(items: list[RubricItem], null_runs: list[dict]) -> list[dict]:
    """Positive items a do-nothing null still earns >= LEAK_THRESHOLD (form/presence rewards)."""
    out = []
    for it in items:
        if it.max_score <= 0:
            continue  # penalties aren't "passed" by doing nothing
        null_max = max((r["per_item"][it.id]["fraction"] for r in null_runs), default=0.0)
        if null_max >= LEAK_THRESHOLD:
            out.append({"id": it.id, "criterion": it.criterion,
                        "null_fraction": round(null_max, 2)})
    return out


def write_tsv(path: Path, header: list[str], rows: list[list]):
    with open(path, "w") as f:
        f.write("\t".join(header) + "\n")
        for r in rows:
            f.write("\t".join(str(x) for x in r) + "\n")
    print(f"  wrote {path.relative_to(config.ROOT)}  ({len(rows)} rows)")
